import React, { useEffect, useState } from "react";
import FAWInput from "../../../../component-widget/FAWInput";
import FAWDropdown from "../../../../component-widget/FAWDropdown";
import FAWCheckbox from "../../../../component-widget/FAWCheckbox";
import FAWItemOptionsEditor from "./shared/FAWItemOptionsEditor";
import EditorShell from "./shared/EditorShell";
import BaseQuestionFields from "./shared/BaseQuestionFields";
import EditorSection from "./shared/EditorSection";

export default function QueDropDownMultiSelectItemEditor({ data, onSave, onClose, saveRef, isDefaultLanguage = true, availableDroplists = [], availableFormFields = [], availableRefDomains = [], domains = [] }) {
  const [item, setItem] = useState(
    data || {
      name: "",
      text: "",
      required: false,
      validationMessage: "",
      horizontalLine: false,
      optionsRefDomain: "",
      options: [],
      optionsPayload: {},
      cloningOptions: { neverClone: false },
    }
  );

  useEffect(() => { if (data) setItem(prev => ({ ...prev, ...data })); }, [data]);
  const handleChange = (field, value) => setItem(prev => ({ ...prev, [field]: value }));
  
  // Handle options payload changes from AtlasItemOptionsEditor
  const handleOptionsChange = (payload) => {
    setItem(prev => ({
      ...prev,
      optionsPayload: payload,
      // Also update the legacy fields for backward compatibility
      optionsRefDomain: payload.optionsRefDomain || prev.optionsRefDomain,
      options: payload.options || prev.options,
    }));
  };
  
  const handleSave = () => { 
    // Process options before saving (like legacy DropDownMultiSelectItemEditor.UpdateSource)
    const processedItem = { ...item };
    
    // Ensure optionsPayload is properly structured for serialization
    if (item.optionsPayload) {
      // The serialization function expects optionsPayload to be at the root level
      processedItem.optionsPayload = item.optionsPayload;
      
      // Also set legacy fields for backward compatibility
      processedItem.optionsRefDomain = item.optionsPayload.optionsRefDomain || item.optionsRefDomain;
      processedItem.options = item.optionsPayload.options || item.options;
    }
    
    onSave?.(processedItem); 
  };

  return (
    <EditorShell onSave={handleSave} onClose={onClose} saveRef={saveRef}>
      <BaseQuestionFields item={item} onChange={setItem} isDefaultLanguage={isDefaultLanguage} questionType="DropDownMultiSelectItemType" />
      
      <EditorSection title="Options Editor">
        <FAWItemOptionsEditor
          options={item.options}
          optionsRefDomain={item.optionsRefDomain}
          defaultMode={item.mode || (item.optionsPayload?.mode)}
          allowConflictFlag={false}
          allowedModes={["RefCode", "StaticList", "Dependency", "FormField"]}
          availableDroplists={availableDroplists}
          availableFormFields={availableFormFields}
          availableRefDomains={availableRefDomains}
          domains={domains}
          isCustomField={item._source?.rc?.Domain === "CustomFields"}
          onChange={handleOptionsChange}
        />
      </EditorSection>
    </EditorShell>
  );
}



